function toArray(value) {
  if (Array.isArray(value)) return value;
  if (value && Array.isArray(value.data)) return value.data;
  if (value && Array.isArray(value.items)) return value.items;
  return [];
}

function escapeHtml(value) {
  return String(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function severity(rag) {
  if (rag === 'Red') return 0;
  if (rag === 'Yellow') return 1;
  if (rag === 'Green') return 2;
  return 3;
}

function getRelation(value) {
  if (Array.isArray(value)) return value[0] || null;
  return value || null;
}

const brief = $('Fetch EOD Brief').item.json;
const updates = toArray($json)
  .map((update) => ({
    ...update,
    project: getRelation(update.project),
    implementation: getRelation(update.implementation)
  }))
  .sort((left, right) => severity(left.rag) - severity(right.rag) || String(left.project?.name || '').localeCompare(String(right.project?.name || '')));

if (updates.length === 0) {
  return [{ json: { subject: brief.subject, html: brief.html, text: brief.text } }];
}

const topUpdates = updates.slice(0, 8);
const htmlSection = `
  <section style="margin-top:24px;">
    <h2 style="font-size:18px;line-height:1.3;margin:0 0 12px;">Project Status Updates</h2>
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0">
      ${topUpdates.map((update) => {
        const projectName = escapeHtml(update.project?.name || 'Unknown project');
        const rag = escapeHtml(update.rag || 'Unknown');
        const summary = escapeHtml(update.summary || 'No summary provided.');
        const nextStep = update.next_step ? `<div style="margin-top:6px;"><strong>Next:</strong> ${escapeHtml(update.next_step)}</div>` : '';
        const decision = update.needs_decision ? `<div style="margin-top:4px;"><strong>Decision:</strong> ${escapeHtml(update.needs_decision)}</div>` : '';
        const blockers = Array.isArray(update.blockers) && update.blockers.length > 0
          ? `<div style="margin-top:4px;"><strong>Blockers:</strong> ${escapeHtml(update.blockers.join('; '))}</div>`
          : '';
        return `<tr><td style="padding:0 0 14px;"><div style="border:1px solid #d0d7de;border-radius:12px;padding:14px;"><div style="font-weight:600;">${projectName} <span style="font-weight:400;">(${rag})</span></div><div style="margin-top:6px;">${summary}</div>${nextStep}${decision}${blockers}</div></td></tr>`;
      }).join('')}
    </table>
  </section>
`;

const textSection = [
  'Project Status Updates:',
  ...topUpdates.flatMap((update) => {
    const lines = [`- ${update.project?.name || 'Unknown project'} (${update.rag || 'Unknown'}): ${update.summary || 'No summary provided.'}`];
    if (update.next_step) lines.push(`  Next: ${update.next_step}`);
    if (update.needs_decision) lines.push(`  Decision: ${update.needs_decision}`);
    if (Array.isArray(update.blockers) && update.blockers.length > 0) lines.push(`  Blockers: ${update.blockers.join('; ')}`);
    return lines;
  })
].join('\n');

return [{
  json: {
    subject: brief.subject,
    html: `${brief.html}${htmlSection}`,
    text: `${brief.text}\n\n${textSection}`
  }
}];
